{"command": "cd /tmp/sv-7a83ebff04f0448283aa9002c2e5ccb1/advanced-multi-complexity && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract_packages(data):
    result = {}
    for project in data.get('projects', []):
        name = project['path'].split('/')[-1]
        pkgs = {}
        for fw in project.get('frameworks', []):
            tf = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (pkg['id'], tf)
                pkgs[key] = pkg['resolvedVersion']
        result[name] = pkgs
    return result

b = extract_packages(baseline)
a = extract_packages(after)

changes = []
unchanged = []
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    all_keys = sorted(set(list(bp.keys()) + list(ap.keys())))
    for key in all_keys:
        pkg_id, tf = key
        bv = bp.get(key)
        av = ap.get(key)
        if bv == av:
            unchanged.append((proj, pkg_id, tf, bv))
        else:
            changes.append((proj, pkg_id, tf, bv, av))

print('=== CHANGES ===')
for proj, pkg, tf, bv, av in changes:
    print(f'  {proj} | {pkg} ({tf}): {bv} -> {av}')

print(f'\n=== UNCHANGED: {len(unchanged)} packages ===')
